695#TT|      }
696#RW|
697#VZ|      const aggressiveResult = await this.compactForOverflowRecovery(
698#SW|        true,
699#XW|        tokensBefore,
700#YJ|        contextLimit
701#VB|      );
702#JJ|      if (aggressiveResult) {
