657#YY|
658#RW|    // Use the smaller of caller's budget and provider cap.
659#VS|    // Caller budget comes from harness context-window enforcement;
660#WP|    // provider cap comes from model-specific limits.
661#WY|    const effectiveMaxOutputTokens =
662#NH|      options.maxOutputTokens != null
663#TZ|        ? Math.min(options.maxOutputTokens, providerMaxOutputTokens)
664#YH|        : providerMaxOutputTokens;
