699#TJ|  ): Promise<UsageMeasurement | null> {
700#PW|    const probeMessages =
701#VB|      messages.length > 0
702#QB|        ? messages
703#SM|        : ([
704#RT|            {
705#XW|              role: "user",
706#MQ|              content: TOKEN_PROBE_SENTINEL,
707#KB|            },
708#YV|          ] satisfies ModelMessage[]);
709#ZY|    const { model, providerOptions } = this.buildModel("off");
710#ZZ|    const preparedMessages =
711#YM|      this.provider === "friendli"
712#JR|        ? applyFriendliInterleavedField(
713#MQ|            probeMessages,
714#TQ|            this.modelId,
715#RV|            DEFAULT_REASONING_MODE
716#WS|          )
717#HY|        : probeMessages;
718#MY|
719#KR|    const agent = createAgent({
720#BQ|      model,
721#HK|      tools: this.toolRegistry,
722#RT|      instructions: await this.getInstructions(),
723#XR|      maxStepsPerTurn: 1,
724#VM|      experimental_repairToolCall: repairToolCall,
725#PH|    });
726#MJ|    const stream = agent.stream({
727#MM|      messages: preparedMessages,
728#VZ|      providerOptions,
729#HP|      maxOutputTokens: 1,
730#QH|    });
731#ZW|    const usage = normalizeUsageMeasurement(
732#TK|      await Promise.all([stream.usage, stream.response]).then(
733#ZN|        ([resolvedUsage]) => {
734#ZS|          return resolvedUsage;
735#VZ|        }
736#WB|      )
737#WR|    );
738#NS|
739#TT|    if (!usage) {
740#NX|      return null;
741#YJ|    }
742#JW|
743#SK|    if (messages.length > 0) {
744#RN|      return usage;
745#KW|    }
746#ZX|
747#SX|    const probeMessageTokens = estimateTokens(TOKEN_PROBE_SENTINEL);
748#XX|    const promptTokens = Math.max(0, usage.promptTokens - probeMessageTokens);
749#YS|    return {
750#NR|      promptTokens,
751#QT|      inputTokens: promptTokens,
752#XN|      completionTokens: usage.completionTokens,
753#NT|      outputTokens: usage.outputTokens,
754#KY|      totalTokens: promptTokens + usage.completionTokens,
755#HX|    };
756#SB|  }
