807#HR|export const computeCompactionMaxTokens = (
808#HB|  contextLength: number,
809#KS|  reserveTokens: number
810#YT|): number => {
811#KV|  if (!(contextLength > 0)) {
812#WH|    return 8000;
813#JR|  }
814#QY|
815#VM|  const usableInputBudget = Math.max(
816#XX|    1,
817#BH|    contextLength - Math.max(0, reserveTokens)
818#MM|  );
819#JY|  return Math.max(1024, Math.floor(usableInputBudget * 0.8));
820#SP|};
